#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007LL

typedef struct Edge {int to; int next;} Edge;

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *val = (int*)malloc((N+1)*sizeof(int));
        for(int i=1;i<=N;i++) scanf("%d", &val[i]);
        // adjacency list using static arrays
        Edge *edges = (Edge*)malloc((N)*sizeof(Edge)); // N-1 edges, allocate N for safety
        int *head = (int*)calloc(N+1, sizeof(int));
        for(int i=1;i<=N;i++) head[i] = -1;
        int ec=0;
        for(int i=0;i<N-1;i++){
            int u,v; scanf("%d %d", &u, &v);
            edges[ec].to = v;
            edges[ec].next = head[u];
            head[u] = ec++;
        }
        // iterative DFS using stack of node and current value
        int *stackNode = (int*)malloc((N+5)*sizeof(int));
        long long *stackVal = (long long*)malloc((N+5)*sizeof(long long));
        int top=0;
        stackNode[top]=1; stackVal[top]=0; top++;
        long long ans=0;
        while(top){
            top--; int u=stackNode[top]; long long cur=stackVal[top];
            cur = (cur*10 + val[u]) % MOD;
            // check if leaf
            if(head[u]==-1){
                ans = (ans + cur) % MOD;
            } else {
                for(int e=head[u]; e!=-1; e=edges[e].next){
                    int v = edges[e].to;
                    stackNode[top]=v; stackVal[top]=cur; top++;
                }
            }
        }
        printf("%lld\n", ans);
        free(val); free(edges); free(head); free(stackNode); free(stackVal);
    }
    return 0;
}

