#include <bits/stdc++.h>
using namespace std;
const long long MOD = 1000000007LL;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> val(N+1);
        for(int i=1;i<=N;i++) cin>>val[i];
        vector<vector<int>> g(N+1);
        for(int i=0;i<N-1;i++){
            int u,v; cin>>u>>v;
            g[u].push_back(v);
        }
        long long ans=0;
        vector<pair<int,long long>> st; // node, current value
        st.reserve(N);
        st.emplace_back(1,0);
        while(!st.empty()){
            auto [u,cur]=st.back(); st.pop_back();
            cur = (cur*10 + val[u]) % MOD;
            if(g[u].empty()) ans = (ans + cur) % MOD;
            else for(int v: g[u]) st.emplace_back(v,cur);
        }
        cout<<ans<<"\n";
    }
    return 0;
}

