#!/usr/bin/env python3
import sys
MOD = 1_000_000_007

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        val = [0] + [int(next(it)) for _ in range(N)]
        g = [[] for _ in range(N+1)]
        for _ in range(N-1):
            u = int(next(it)); v = int(next(it))
            g[u].append(v)
        ans = 0
        stack = [(1, 0)]  # node, current value
        while stack:
            u, cur = stack.pop()
            cur = (cur * 10 + val[u]) % MOD
            if not g[u]:
                ans = (ans + cur) % MOD
            else:
                for v in g[u]:
                    stack.append((v, cur))
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

